import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, Navigate } from 'react-router-dom';
import axios from 'axios';
import Login from './pages/Login';
import Signup from './pages/Signup';
import RegisterComplaint from './pages/RegisterComplaint';

function App() {
  const [complaints, setComplaints] = useState([]);
  // Check kar rahe hain ki user pehle se login hai ya nahi
  const [token, setToken] = useState(localStorage.getItem('token'));

  // 1. Backend se data fetch karne ka function
  const fetchComplaints = async () => {
    try {
      const response = await axios.get('http://127.0.0.1:8000/api/complaints/');
      setComplaints(response.data);
    } catch (err) {
      console.error("Backend se connect nahi ho pa raha", err);
    }
  };

  // 2. Agar token hai to hi data load karein
  useEffect(() => {
    if (token) {
      fetchComplaints();
    }
  }, [token]);

  // 3. Status update (Resolve) karne ka function
  const handleResolve = async (id) => {
    try {
      await axios.put(`http://127.0.0.1:8000/api/complaints/${id}/resolve`);
      alert("Status Updated Successfully!");
      fetchComplaints();
    } catch (err) {
      console.error("Update fail ho gaya", err);
    }
  };

  // 4. Logout function
  const handleLogout = () => {
    localStorage.removeItem('token');
    setToken(null);
    window.location.href = "/login";
  };

  return (
    <Router>
      {/* Navigation Bar */}
      <nav style={{ 
        padding: '15px 20px', 
        background: '#2c3e50', 
        color: 'white', 
        display: 'flex', 
        justifyContent: 'space-between',
        alignItems: 'center'
      }}>
        <Link to="/" style={{ color: 'white', textDecoration: 'none', fontWeight: 'bold', fontSize: '20px' }}>
          Grievance System
        </Link>
        <div>
          {!token ? (
            <>
              <Link to="/login" style={{ color: 'white', marginRight: '15px', textDecoration: 'none' }}>Login</Link>
              <Link to="/signup" style={{ color: 'white', textDecoration: 'none' }}>Signup</Link>
            </>
          ) : (
            <button onClick={handleLogout} style={{ 
              background: '#e74c3c', 
              color: 'white', 
              border: 'none', 
              padding: '5px 15px', 
              borderRadius: '3px',
              cursor: 'pointer' 
            }}>Logout</button>
          )}
        </div>
      </nav>

      <Routes>
        {/* Login aur Signup Routes */}
        <Route path="/login" element={!token ? <Login /> : <Navigate to="/" />} />
        <Route path="/signup" element={!token ? <Signup /> : <Navigate to="/" />} />

        {/* Home Route (Protected: Sirf login users ke liye) */}
        <Route path="/" element={token ? (
          <div style={{ padding: '20px', fontFamily: 'Arial', maxWidth: '800px', margin: '0 auto' }}>
            <h1 style={{ color: '#2c3e50', textAlign: 'center' }}>Dashboard</h1>
            <hr />
            
            <RegisterComplaint onRefresh={fetchComplaints} />

            <div style={{ marginTop: '30px' }}>
              <h3>Your Registered Complaints:</h3>
              {complaints.length === 0 ? (
                <p style={{ color: 'gray' }}>No complaints found.</p>
              ) : (
                <ul style={{ listStyleType: 'none', padding: 0 }}>
                  {complaints.map((c) => (
                    <li key={c.id} style={{ 
                      padding: '15px', 
                      borderBottom: '1px solid #ddd', 
                      backgroundColor: '#f9f9f9',
                      marginBottom: '10px',
                      borderRadius: '5px'
                    }}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                        <div>
                          <b style={{ fontSize: '18px' }}>{c.title}</b> <br />
                          <small style={{ color: '#555' }}>Category: {c.category}</small>
                        </div>
                        <div>
                          <span style={{ color: c.status === 'Pending' ? 'orange' : 'green', fontWeight: 'bold', marginRight: '15px' }}> 
                            {c.status} 
                          </span>
                          {c.status === 'Pending' && (
                            <button onClick={() => handleResolve(c.id)} style={{ padding: '5px 10px', backgroundColor: '#2ecc71', color: 'white', border: 'none', borderRadius: '3px', cursor: 'pointer' }}>
                              Resolve
                            </button>
                          )}
                        </div>
                      </div>
                      <p style={{ marginTop: '10px', color: '#333' }}>{c.description}</p>
                    </li>
                  ))}
                </ul>
              )}
            </div>
          </div>
        ) : <Navigate to="/login" />} />
      </Routes>
    </Router>
  );
}

export default App;
